    content: '';
    position: absolute;
    inset: 0;
    border-radius: inherit;
    padding: 1px;
    background: linear-gradient(135deg, hsl(var(--primary) / 0.4), hsl(var(--accent) / 0.2));
    -webkit-mask:
      linear-gradient(#fff 0 0) content-box,
      linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
    mask-composite: exclude;
    pointer-events: none;
  }

  /* Improved gradient for dark mode */
  [data-theme='dark'] .gradient-border::before {
    background: linear-gradient(135deg, hsl(var(--primary) / 0.6), hsl(var(--accent) / 0.4));
  }

  .glass-card {
    background: hsl(var(--card) / 0.6);
    backdrop-filter: blur(12px);
    border: 1px solid hsl(var(--border));
  }
}

html {
  opacity: 0;
}

html[data-theme='dark'],
html[data-theme='light'] {
  opacity: initial;
}

/* Rich Text Content Styles */
.rich-text-content {
  p {
    @apply my-2 first:mt-0 last:mb-0;
  }

  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    @apply mt-6 mb-3 font-semibold text-foreground leading-tight first:mt-0;
  }

  h1 {
    @apply text-3xl;
  }
  h2 {
    @apply text-2xl;
  }
  h3 {
    @apply text-xl;
  }
  h4 {
    @apply text-lg;
  }

  ul,
  ol {
    @apply my-3 pl-6;

    li {
      @apply my-1;
    }
  }

  strong {
    @apply font-semibold text-foreground;
  }

  em {
    @apply italic;
  }

  a {
    @apply text-primary underline underline-offset-2 transition-colors hover:text-primary/80;
  }

  code {
    @apply bg-muted text-foreground px-1.5 py-0.5 rounded text-sm font-mono;
  }

  pre {
    @apply bg-muted p-4 rounded-lg overflow-x-auto my-4 border border-border;

    code {
      @apply bg-transparent p-0 text-sm;
    }
  }

  blockquote {
    @apply border-l-4 border-primary my-4 pl-4 text-muted-foreground italic;
  }

  hr {
    @apply border-0 border-t border-border my-6;
  }

  img {
    @apply max-w-full h-auto rounded-lg my-4;
  }

  table {
    @apply w-full border-collapse my-4;

    th,
    td {
      @apply p-2 border border-border text-left;
    }

    th {
      @apply bg-muted font-semibold;
    }
  }

  /* KaTeX math rendering */
  .katex {
    @apply text-foreground;
    font-size: 1.1em;
  }

  .katex-display {
    @apply my-5 overflow-x-auto overflow-y-hidden py-2;

    /* Scrollbar styling for dark mode support */
    &::-webkit-scrollbar {
      height: 8px;
    }

    &::-webkit-scrollbar-track {
      @apply bg-muted rounded;
    }

    &::-webkit-scrollbar-thumb {
      @apply bg-border rounded hover:bg-muted-foreground/50;
    }
  }

  .katex-inline {
    @apply inline-block;
  }
}

/* MathLive mathfield theming */
math-field {
  --primary: hsl(var(--primary));
  --caret-color: hsl(var(--foreground));
  --selection-background-color: hsl(var(--accent));
  --selection-color: hsl(var(--accent-foreground));
  --placeholder-color: hsl(var(--muted-foreground));
  --placeholder-opacity: 0.5;
  font-size: 1.1em;
  border: 1px solid hsl(var(--border));
  border-radius: var(--radius);
  padding: 0.5rem 0.75rem;
  background: hsl(var(--input));
  color: hsl(var(--foreground));
  min-height: 2.5rem;
  width: 100%;
  direction: ltr;
}

math-field:focus-within {
  outline: 2px solid hsl(var(--ring));
  outline-offset: 2px;
}

/* Exercise View Animations */
@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.animate-slide-up {
  animation: slideUp 0.3s ease;
}

.animate-fade-in {
  animation: fadeIn 0.3s ease;
}

/* Scrollbar hide utility */
.scrollbar-none {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-none::-webkit-scrollbar {
  display: none;
}

/* RTL/LTR Isolation for Math - must be flat selectors */
.math-inline {
  direction: ltr;
  unicode-bidi: isolate;
  display: inline-block;
  vertical-align: middle;
}

.math-block {
  direction: ltr;
  unicode-bidi: isolate;
  display: block;
  text-align: center;
  margin-top: 0.75rem;
  margin-bottom: 0.75rem;
}

/* KaTeX math expression styling in chat */
.chat-message-content .katex {
  @apply bg-muted text-foreground p-5 rounded-xl inline-block;
  margin: calc(var(--spacing) * 1);
}

/* Dark mode: keep original secondary background */
[data-theme='dark'] .chat-message-content .katex {
  @apply bg-secondary text-secondary-foreground;
}

/* KaTeX in user messages: inherit background from parent (primary) */
.bg-primary .chat-message-content .katex {
  @apply bg-inherit text-inherit;
}

/* Chat table: reset KaTeX math padding inside table cells */
.chat-message-content .chat-table .katex {
  @apply bg-transparent p-0 m-0 rounded-none text-primary;
  font-size: 1em;
}

[data-theme='dark'] .chat-message-content .chat-table .katex {
  @apply bg-transparent text-primary;
}

/* ===================================================================
   Color Syntax Support
   =================================================================== */

/* Text highlight classes for ::text-highlight-N{} markdown syntax (exercise editor) */
.aguy-text-highlight-1 {
  color: hsl(var(--text-highlight-1));
}

.aguy-text-highlight-2 {
  color: hsl(var(--text-highlight-2));
}

.aguy-text-highlight-3 {
  color: hsl(var(--text-highlight-3));
}

.aguy-text-highlight-4 {
  color: hsl(var(--text-highlight-4));
}

.aguy-text-highlight-5 {
  color: hsl(var(--text-highlight-5));
}

.aguy-text-highlight-6 {
  color: hsl(var(--text-highlight-6));
}

.aguy-text-highlight-7 {
  color: hsl(var(--text-highlight-7));
}

.aguy-text-highlight-8 {
  color: hsl(var(--text-highlight-8));
}

