'use client'

import { motion } from 'framer-motion'
import { useTranslations } from '@/ui/web/providers/I18n'
import { cn } from '@/infra/utils/ui'
import { X } from 'lucide-react'

/**
 * @fileType component
 * @domain study-mode
 * @pattern chat-panel
 * @ai-summary Slide-in chat panel for Hint/Ask mode
 */

interface ChatSlidePanelProps {
  children: React.ReactNode
  onClose: () => void
  className?: string
}

export function ChatSlidePanel({ children, onClose, className }: ChatSlidePanelProps) {
  const t = useTranslations('studyMode')
  const [prefersReducedMotion, setPrefersReducedMotion] = React.useState(false)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)')
    setPrefersReducedMotion(mediaQuery.matches)

    const handler = (e: MediaQueryListEvent) => setPrefersReducedMotion(e.matches)
    mediaQuery.addEventListener('change', handler)
    return () => mediaQuery.removeEventListener('change', handler)
  }, [])

  // Determine slide direction based on RTL
  const isRtl = document.body.dir === 'rtl'
  const slideFrom = isRtl ? '-left' : '-right'

  return (
    <>
      {/* Backdrop */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 bg-black/30 z-40 lg:hidden"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Slide panel */}
      <motion.div
        initial={prefersReducedMotion ? {} : { x: `100%${slideFrom}` }}
        animate={{ x: 0 }}
        exit={prefersReducedMotion ? {} : { x: `100%${slideFrom}` }}
        transition={{ type: 'spring', duration: 0.3 }}
        className={cn(
          'fixed top-0 end-0 h-full w-full max-w-md z-50',
          'glass-surface rounded-s-4xl',
          'border-s border-mode-border/20',
          'flex flex-col',
          className
        )}
        role="dialog"
        aria-label={t('chat.panelLabel')}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-mode-border/20">
          <h2 className="font-semibold">{t('chat.panelLabel')}</h2>
          <button
            onClick={onClose}
            className={cn(
              'p-2 rounded-full hover:bg-mode-surface/50 transition-colors',
              'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-mode-accent',
              'min-h-[48px] min-w-[48px] flex items-center justify-center'
            )}
            aria-label={t('chat.slideOut')}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto">
          {children}
        </div>
      </motion.div>
    </>
  )
}

'use client'

import { motion } from 'framer-motion'
import { useEffect, useState } from 'react'
import { useTranslations } from '@/ui/web/providers/I18n'
import { cn } from '@/infra/utils/ui'
import { Play, Pause, AlertTriangle } from 'lucide-react'

/**
 * @fileType component
 * @domain study-mode
 * @pattern timer
 * @ai-summary Floating timer for Test mode
 */

interface TestModeTimerProps {
  className?: string
  durationMinutes?: number
  onTimerEnd?: () => void
}

export function TestModeTimer({
  className,
  durationMinutes = 60,
  onTimerEnd,
}: TestModeTimerProps) {
  const t = useTranslations('studyMode')
  const [secondsRemaining, setSecondsRemaining] = useState(durationMinutes * 60)
  const [isPaused, setIsPaused] = useState(false)
  const [isExpired, setIsExpired] = useState(false)

  // Load from sessionStorage on mount
  useEffect(() => {
    const saved = sessionStorage.getItem('test-timer')
    if (saved) {
      const { remaining, timestamp } = JSON.parse(saved)
      const elapsed = Math.floor((Date.now() - timestamp) / 1000)
      const remainingAfterLoad = remaining - elapsed
      if (remainingAfterLoad > 0) {
        setSecondsRemaining(remainingAfterLoad)
      } else {
        setIsExpired(true)
        setSecondsRemaining(0)
      }
    }
  }, [])

  // Save to sessionStorage periodically
  useEffect(() => {
    if (isExpired || isPaused) return

    const interval = setInterval(() => {
      sessionStorage.setItem(
        'test-timer',
        JSON.stringify({
          remaining: secondsRemaining,
          timestamp: Date.now(),
        })
      )
    }, 1000)

    return () => clearInterval(interval)
  }, [secondsRemaining, isPaused, isExpired])

  // Countdown
  useEffect(() => {
    if (isPaused || isExpired) return

    const interval = setInterval(() => {
      setSecondsRemaining((prev) => {
        if (prev <= 1) {
          setIsExpired(true)
          onTimerEnd?.()
          return 0
        }
        return prev - 1
      })
    }, 1000)

    return () => clearInterval(interval)
  }, [isPaused, isExpired, onTimerEnd])

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`
  }

  const handleTogglePause = () => {
    setIsPaused(!isPaused)
  }

  const isLowTime = secondsRemaining <= 300 // 5 minutes

  return (
    <motion.div
      initial={{ scale: 0.9, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      className={cn(
        'glass-surface rounded-full px-4 py-2',
        'border border-mode-accent/30',
        'flex items-center gap-3',
        isLowTime && isExpired && 'border-error bg-error/10',
        className
      )}
      role="timer"
      aria-live="polite"
      aria-atomic="true"
    >
      {/* Timer icon */}
      <div className={cn(
        'w-8 h-8 rounded-full flex items-center justify-center',
        isLowTime && !isExpired ? 'bg-warning/20 text-warning' : 'bg-mode-accent/20 text-mode-accent'
      )}>
        {isExpired ? (
          <AlertTriangle className="w-4 h-4" />
        ) : (
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        )}
      </div>

      {/* Time display */}
      <div className="flex flex-col">
        <span className={cn(
          'text-lg font-mono font-semibold',
          isLowTime && !isExpired && 'text-warning',
          isExpired && 'text-error'
        )}>
          {isExpired ? t('testMode.timerExpired') : formatTime(secondsRemaining)}
        </span>
        {!isExpired && (
          <span className="text-xs text-muted-foreground">
            {t('timer.remaining')}
          </span>
        )}
      </div>

      {/* Pause/Resume button */}
      {!isExpired && (
        <button
          onClick={handleTogglePause}
          className={cn(
            'p-2 rounded-full hover:bg-mode-surface/50 transition-colors',
            'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-mode-accent',
            'min-h-[48px] min-w-[48px] flex items-center justify-center'
          )}
          aria-label={isPaused ? t('timer.resume') : t('timer.pause')}
        >
          {isPaused ? (
            <Play className="w-4 h-4" />
          ) : (
            <Pause className="w-4 h-4" />
          )}
        </button>
      )}

      {/* Safe area padding for mobile */}
      <div className="pb-[env(safe-area-inset-bottom)]" />
    </motion.div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { useTranslations } from '@/ui/web/providers/I18n'
import { cn } from '@/infra/utils/ui'
import { useStudyMode } from '@/ui/web/providers/StudyMode'

/**
 * @fileType component
 * @domain study-mode
 * @pattern navigation-guard
 * @ai-summary Test mode guard that restricts navigation during test mode
 */

interface TestModeGuardProps {
  children: React.ReactNode
  className?: string
}

export function TestModeGuard({ children, className }: TestModeGuardProps) {
  const t = useTranslations('studyMode')
  const { mode, setMode } = useStudyMode()
  const router = useRouter()
  const [showConfirmDialog, setShowConfirmDialog] = useState(false)
  const [pendingNavigation, setPendingNavigation] = useState<(() => void) | null>(null)

  // Warn before leaving the page during test mode
  useEffect(() => {
    if (mode !== 'test') return

    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault()
      e.returnValue = t('testMode.confirmLeave')
      return t('testMode.confirmLeave')
    }

    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  }, [mode, t])

  // Restrict navigation in test mode
  useEffect(() => {
    if (mode !== 'test') return

    const handlePopState = () => {
      // Block back navigation
      window.history.forward()
    }

    window.addEventListener('popstate', handlePopState)
    return () => window.removeEventListener('popstate', handlePopState)
  }, [mode])

  const handleNavigationAttempt = (navigationAction: () => void) => {
    if (mode !== 'test') {
      navigationAction()
      return
    }

    // Show confirmation dialog
    setPendingNavigation(() => navigationAction)
    setShowConfirmDialog(true)
  }

  const confirmNavigation = () => {
    setShowConfirmDialog(false)
    pendingNavigation?.()
    setPendingNavigation(null)
  }

  const cancelNavigation = () => {
    setShowConfirmDialog(false)
    setPendingNavigation(null)
  }

  const exitTestMode = () => {
    setMode('study')
    setShowConfirmDialog(false)
    setPendingNavigation(null)
  }

  return (
    <>
      <div className={className}>
        {children}
      </div>

      {/* Confirmation Dialog */}
      {showConfirmDialog && (
        <div
          className="fixed inset-0 z-[100] flex items-center justify-center p-4"
          role="alertdialog"
          aria-modal="true"
          aria-labelledby="test-mode-dialog-title"
          aria-describedby="test-mode-dialog-desc"
        >
          {/* Backdrop */}
          <div
            className="absolute inset-0 bg-black/50"
            onClick={cancelNavigation}
            aria-hidden="true"
          />

          {/* Dialog */}
          <div className="relative glass-surface rounded-4xl p-6 max-w-sm w-full">
            <h3
              id="test-mode-dialog-title"
              className="text-lg font-semibold mb-2"
            >
              {t('testMode.restrictedNav')}
            </h3>
            <p
              id="test-mode-dialog-desc"
