  lessonTitle: string
  lessonId: string
  exercises: ExerciseItem[]
  backUrl?: string
  chatContent?: React.ReactNode
  className?: string
}

/**
 * Inner workspace component that uses the context
 */
function StudyingWorkspaceInner({
  children,
  lessonTitle,
  lessonId,
  exercises,
  backUrl,
  chatContent,
  className,
}: StudyingWorkspaceProps) {
