  const t = useTranslations('studyMode')
  const { mode, setMode } = useStudyMode()
  const [showConfirmDialog, setShowConfirmDialog] = useState(false)
  const [pendingNavigation, setPendingNavigation] = useState<(() => void) | null>(null)

